#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,C; scanf("%lld %lld %lld", &A, &B, &C);
        if(A==B || A==C || B==C) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

